mapper.select:
SELECT ic.*, t.name as tenantName, t.status as tenantStatus FROM im_invite_code ic LEFT JOIN system_tenant t ON ic.tenant_id = t.id WHERE ic.deleted = 0
AND ic.code LIKE CONCAT('%', #{ew.code}, '%')
AND ic.type = #{ew.type}
AND ic.status = #{ew.status}
AND ic.creator_name LIKE CONCAT('%', #{ew.creatorName}, '%')
AND t.name LIKE CONCAT('%', #{ew.tenantName}, '%')
AND ic.create_time BETWEEN #{ew.createTime[0]} AND #{ew.createTime[1]}
AND ic.tenant_id = #{ew.tenantId}
ORDER BY ic.id DESC
